// Generated by OrchestKit Claude Plugin
// Created: 2026-03-04

/**
 * Performance Snapshot — Stop Hook
 *
 * Fires at session end (Stop event). Reads the token-tracker state for this
 * session, counts hook injections by category and by hook name, and writes a
 * JSON snapshot to ~/.claude/perf/snap-{YYYY-MM-DD-HH}.json.
 *
 * Purpose: before/after token-overhead comparison for performance sprints.
 * Returns a systemMessage for logging/test-visibility. Note: when registered
 * inside the async stop/unified-dispatcher, the return value is discarded by
 * the dispatcher (it always returns outputSilentSuccess). The snapshot data
 * is written to disk regardless and that is the primary output.
 *
 * Hook: Stop (registered inside stop/unified-dispatcher as an async member)
 */

import { mkdirSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult , HookContext} from '../types.js';
import { logHook, outputSilentSuccess } from '../lib/common.js';
import { getTokenState } from '../lib/token-tracker.js';
import { getHomeDir } from '../lib/paths.js';
import { atomicWriteSync } from '../lib/atomic-write.js';

const HOOK_NAME = 'perf-snapshot';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface PerfSnapshot {
  schemaVersion: 1;
  capturedAt: string;
  /** YYYY-MM-DD-HH bucket — one snapshot per hour, newer overwrites */
  bucket: string;
  sessionId: string;
  totalTokensInjected: number;
  byCategory: Record<string, number>;
  byHook: Record<string, number>;
  /** Derived: top-3 categories by token count */
  topCategories: Array<{ category: string; tokens: number }>;
  hookCount: number;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function getPerfDir(): string {
  return join(getHomeDir(), '.claude', 'perf');
}

function getBucket(): string {
  const now = new Date();
  const yyyy = now.getFullYear();
  const mm = String(now.getMonth() + 1).padStart(2, '0');
  const dd = String(now.getDate()).padStart(2, '0');
  const hh = String(now.getHours()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}-${hh}`;
}

function topN<T extends Record<string, number>>(
  map: T,
  n: number
): Array<{ category: string; tokens: number }> {
  return Object.entries(map)
    .sort(([, a], [, b]) => b - a)
    .slice(0, n)
    .map(([category, tokens]) => ({ category, tokens }));
}

function buildSummaryLines(snapshot: PerfSnapshot): string {
  const top = snapshot.topCategories
    .map(c => `${c.category}:${c.tokens}t`)
    .join(', ');
  const hookWord = snapshot.hookCount === 1 ? 'hook' : 'hooks';
  return [
    `[perf-snapshot] Total injected: ${snapshot.totalTokensInjected} tokens across ${snapshot.hookCount} ${hookWord}`,
    `[perf-snapshot] Top categories: ${top || 'none'}`,
    `[perf-snapshot] Snapshot: ~/.claude/perf/snap-${snapshot.bucket}.json`,
  ].join('\n');
}

// ---------------------------------------------------------------------------
// Main export
// ---------------------------------------------------------------------------

/**
 * Check if perf snapshot is enabled.
 * Configurable via ORCHESTKIT_PERF_SNAPSHOT_ENABLED env var (set in ork.settings.json).
 * Default: enabled ("1" | "true" | "" = on; "0" | "false" = off)
 */
function isPerfSnapshotEnabled(): boolean {
  const val = process.env.ORCHESTKIT_PERF_SNAPSHOT_ENABLED?.toLowerCase().trim();
  if (val === '0' || val === 'false') return false;
  return true;
}

export function perfSnapshot(_input: HookInput, ctx?: HookContext): HookResult {
  if (!isPerfSnapshotEnabled()) {
    return outputSilentSuccess();
  }

  try {
    const tokenState = getTokenState();
    const bucket = getBucket();
    const perfDir = getPerfDir();

    const topCategories = topN(tokenState.byCategory, 3);
    const hookCount = Object.keys(tokenState.byHook).length;

    const snapshot: PerfSnapshot = {
      schemaVersion: 1,
      capturedAt: new Date().toISOString(),
      bucket,
      sessionId: tokenState.sessionId,
      totalTokensInjected: tokenState.totalTokensInjected,
      byCategory: tokenState.byCategory,
      byHook: tokenState.byHook,
      topCategories,
      hookCount,
    };

    mkdirSync(perfDir, { recursive: true });
    const snapPath = join(perfDir, `snap-${bucket}.json`);
    atomicWriteSync(snapPath, JSON.stringify(snapshot, null, 2));

    (ctx?.log ?? logHook)(
      HOOK_NAME,
      `Snapshot written: snap-${bucket}.json (${tokenState.totalTokensInjected}t, ${hookCount} hooks)`
    );

    const summary = buildSummaryLines(snapshot);
    return {
      continue: true,
      systemMessage: summary,
    };
  } catch (err) {
    (ctx?.log ?? logHook)(
      HOOK_NAME,
      `Failed to write snapshot: ${err instanceof Error ? err.message : String(err)}`,
      'warn'
    );
    return outputSilentSuccess();
  }
}
